<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <title>Snake Game</title>
  <style>
    /* Dark Theme Styling */
    body {
      background-color: #121212;
      color: #e0e0e0;
      font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
      display: flex;
      flex-direction: column;
      align-items: center;
      justify-content: center;
      min-height: 100vh;
      margin: 0;
      padding: 20px;
      box-sizing: border-box;
    }

    h1 {
      margin: 0 0 10px 0;
      font-size: 2.5rem;
      color: #4caf50;
      text-shadow: 0 0 10px rgba(76, 175, 80, 0.3);
    }

    .score-container {
      font-size: 1.5rem;
      margin-bottom: 15px;
      font-weight: bold;
    }

    #score {
      color: #4caf50;
    }

    /* Canvas Board - at least 400x400 CSS pixels */
    #snake {
      background-color: #1e1e1e;
      border: 4px solid #333;
      border-radius: 8px;
      box-shadow: 0 10px 30px rgba(0, 0, 0, 0.5);
      display: block;
      width: 400px;
      height: 400px;
    }

    /* Controls */
    .controls {
      margin-top: 20px;
      display: flex;
      gap: 15px;
    }

    button {
      background-color: #333;
      color: #fff;
      border: 2px solid #555;
      padding: 10px 20px;
      font-size: 1rem;
      font-weight: bold;
      border-radius: 5px;
      cursor: pointer;
      transition: all 0.2s ease;
    }

    button:hover {
      background-color: #4caf50;
      border-color: #4caf50;
      color: #121212;
      box-shadow: 0 0 8px rgba(76, 175, 80, 0.5);
    }

    button:active {
      transform: scale(0.95);
    }

    .instructions {
      margin-top: 20px;
      font-size: 0.9rem;
      color: #888;
      text-align: center;
      max-width: 400px;
      line-height: 1.4;
    }
  </style>
</head>
<body>

  <h1>SNAKE</h1>
  <div class="score-container">Score: <span id="score">0</span></div>

  <canvas id="snake" width="400" height="400"></canvas>

  <div class="controls">
    <button id="start">Start</button>
    <button id="pause">Pause</button>
    <button id="reset">Reset</button>
  </div>

  <div class="instructions">
    Use the <strong>Arrow Keys</strong> to steer the snake. Avoid hitting the walls or your own body!
  </div>

  <script>
    // Grid configuration (20x20 cells)
    const GRID_W = 20;
    const GRID_H = 20;

    // Canvas and Context
    const canvas = document.getElementById('snake');
    const ctx = canvas.getContext('2d');
    const scoreEl = document.getElementById('score');

    // Game State Variables
    let snake = [];      // Array of [x, y], head first
    let food = [0, 0];   // [x, y]
    let direction = 'right'; // Current moving direction
    let nextDirection = 'right'; // Queued direction for next tick
    let isAlive = true;
    let currentScore = 0;
    let gameInterval = null;
    const GAME_SPEED = 150; // ms per tick

    // Helper to generate random food position not on the snake
    function generateRandomFood() {
      const freeCells = [];
      for (let x = 0; x < GRID_W; x++) {
        for (let y = 0; y < GRID_H; y++) {
          // Check if cell is occupied by snake
          const onSnake = snake.some(segment => segment[0] === x && segment[1] === y);
          if (!onSnake) {
            freeCells.push([x, y]);
          }
        }
      }
      if (freeCells.length > 0) {
        const randomIndex = Math.floor(Math.random() * freeCells.length);
        food = freeCells[randomIndex];
      }
    }

    // Render the game board
    function draw() {
      // Clear canvas
      ctx.fillStyle = '#1e1e1e';
      ctx.fillRect(0, 0, canvas.width, canvas.height);

      const cellW = canvas.width / GRID_W;
      const cellH = canvas.height / GRID_H;

      // Draw Food
      ctx.fillStyle = '#ff5252';
      ctx.beginPath();
      const foodX = food[0] * cellW + cellW / 2;
      const foodY = food[1] * cellH + cellH / 2;
      const radius = Math.min(cellW, cellH) / 2 - 2;
      ctx.arc(foodX, foodY, radius, 0, 2 * Math.PI);
      ctx.fill();

      // Draw Snake
      snake.forEach((segment, index) => {
        const isHead = index === 0;
        ctx.fillStyle = isHead ? '#81c784' : '#4caf50';

        const x = segment[0] * cellW + 1;
        const y = segment[1] * cellH + 1;
        const w = cellW - 2;
        const h = cellH - 2;

        // Rounded rectangle for snake segments
        ctx.beginPath();
        ctx.roundRect ? ctx.roundRect(x, y, w, h, 4) : ctx.rect(x, y, w, h);
        ctx.fill();

        // Draw eyes on the head
        if (isHead) {
          ctx.fillStyle = '#121212';
          const eyeSize = 3;
          if (direction === 'right' || direction === 'left') {
            const eyeX = direction === 'right' ? x + w - 6 : x + 4;
            ctx.fillRect(eyeX, y + 4, eyeSize, eyeSize);
            ctx.fillRect(eyeX, y + h - 7, eyeSize, eyeSize);
          } else {
            const eyeY = direction === 'down' ? y + h - 6 : y + 4;
            ctx.fillRect(x + 4, eyeY, eyeSize, eyeSize);
            ctx.fillRect(x + w - 7, eyeY, eyeSize, eyeSize);
          }
        }
      });

      // Update score display
      scoreEl.textContent = currentScore;

      // Draw Game Over overlay
      if (!isAlive) {
        ctx.fillStyle = 'rgba(0, 0, 0, 0.75)';
        ctx.fillRect(0, 0, canvas.width, canvas.height);
        ctx.fillStyle = '#ff5252';
        ctx.font = 'bold 30px sans-serif';
        ctx.textAlign = 'center';
        ctx.textBaseline = 'middle';
        ctx.fillText('GAME OVER', canvas.width / 2, canvas.height / 2);
      }
    }

    // Programmatic API implementation
    window.game = {
      w: GRID_W,
      h: GRID_H,

      reset() {
        // Initialize snake with length 3 in the middle, moving right
        const startX = Math.floor(GRID_W / 2);
        const startY = Math.floor(GRID_H / 2);
        snake = [
          [startX, startY],
          [startX - 1, startY],
          [startX - 2, startY]
        ];
        direction = 'right';
        nextDirection = 'right';
        isAlive = true;
        currentScore = 0;
        generateRandomFood();
        draw();
      },

      tick() {
        if (!isAlive) return;

        // Commit the queued direction
        direction = nextDirection;

        // Calculate next head position
        const head = snake[0];
        let nextHead = [head[0], head[1]];

        if (direction === 'up') nextHead[1] -= 1;
        else if (direction === 'down') nextHead[1] += 1;
        else if (direction === 'left') nextHead[0] -= 1;
        else if (direction === 'right') nextHead[0] += 1;

        // Check wall collision
        if (nextHead[0] < 0 || nextHead[0] >= GRID_W || nextHead[1] < 0 || nextHead[1] >= GRID_H) {
          isAlive = false;
          draw();
          return;
        }

        // Check self collision (excluding the tail tip if we aren't eating, but to be safe and strict,
        // we check against all current segments because the tail moves forward unless food is eaten)
        const isEating = (nextHead[0] === food[0] && nextHead[1] === food[1]);
        const collisionBody = isEating ? snake : snake.slice(0, -1);
        const selfCollision = collisionBody.some(segment => segment[0] === nextHead[0] && segment[1] === nextHead[1]);

        if (selfCollision) {
          isAlive = false;
          draw();
          return;
        }

        // Move head
        snake.unshift(nextHead);

        if (isEating) {
          currentScore += 1;
          generateRandomFood();
        } else {
          // Remove tail
          snake.pop();
        }

        draw();
      },

      setDir(dir) {
        // Validate direction and ignore 180-degree reversals
        if (dir === 'up' && direction !== 'down') nextDirection = 'up';
        if (dir === 'down' && direction !== 'up') nextDirection = 'down';
        if (dir === 'left' && direction !== 'right') nextDirection = 'left';
        if (dir === 'right' && direction !== 'left') nextDirection = 'right';
      },

      setFood(x, y) {
        food = [x, y];
        draw();
      },

      snake() {
        return snake;
      },

      food() {
        return food;
      },

      alive() {
        return isAlive;
      },

      score() {
        return currentScore;
      }
    };

    // Keyboard Controls
    window.addEventListener('keydown', (e) => {
      if (e.key === 'ArrowUp') {
        window.game.setDir('up');
        e.preventDefault();
      } else if (e.key === 'ArrowDown') {
        window.game.setDir('down');
        e.preventDefault();
      } else if (e.key === 'ArrowLeft') {
        window.game.setDir('left');
        e.preventDefault();
      } else if (e.key === 'ArrowRight') {
        window.game.setDir('right');
        e.preventDefault();
      }
    });

    // Button Controls
    const startBtn = document.getElementById('start');
    const pauseBtn = document.getElementById('pause');
    const resetBtn = document.getElementById('reset');

    function startAutoAdvance() {
      if (!gameInterval && isAlive) {
        gameInterval = setInterval(() => {
          window.game.tick();
          if (!isAlive) {
            clearInterval(gameInterval);
            gameInterval = null;
          }
        }, GAME_SPEED);
      }
    }

    function pauseAutoAdvance() {
      if (gameInterval) {
        clearInterval(gameInterval);
        gameInterval = null;
      }
    }

    startBtn.addEventListener('click', startAutoAdvance);
    pauseBtn.addEventListener('click', pauseAutoAdvance);
    resetBtn.addEventListener('click', () => {
      pauseAutoAdvance();
      window.game.reset();
    });

    // Initialize Game on Load
    window.game.reset();
  </script>
</body>
</html>
